<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Personal Expense Tracker</title>
<style>
  body {font-family: Arial, sans-serif; max-width: 800px; margin: 20px auto; padding:0 10px;}
  h1 {text-align:center;}
  form, .filters, .summary {margin-bottom:20px; padding:10px; border:1px solid #ccc; border-radius:5px;}
  label {display:inline-block; width:80px; margin-right:5px;}
  input, select {margin-bottom:5px;}
  #form-error {color:red; margin-top:5px;}
  .expense {display:flex; justify-content:space-between; padding:5px; border-bottom:1px solid #eee;}
  .expense span {margin-right:10px;}
  .exp-del {background:#e74c3c; color:#fff; border:none; padding:2px 6px; cursor:pointer;}
  .summary {display:flex; justify-content:space-between; align-items:center;}
  .cat-total {margin-right:15px;}
</style>
</head>
<body>
<h1>Personal Expense Tracker</h1>

<form id="expense-form">
  <div>
    <label for="amount">Amount:</label>
    <input type="number" id="amount" step="0.01" min="0">
  </div>
  <div>
    <label for="category">Category:</label>
    <select id="category">
      <option value="groceries">groceries</option>
      <option value="transport">transport</option>
      <option value="bills">bills</option>
      <option value="fun">fun</option>
    </select>
  </div>
  <div>
    <label for="date">Date:</label>
    <input type="date" id="date">
  </div>
  <div>
    <label for="note">Note:</label>
    <input type="text" id="note" placeholder="optional">
  </div>
  <button type="button" id="add-expense">Add Expense</button>
  <div id="form-error"></div>
</form>

<div class="filters">
  <label for="filter-category">Category:</label>
  <select id="filter-category">
    <option value="all">all</option>
    <option value="groceries">groceries</option>
    <option value="transport">transport</option>
    <option value="bills">bills</option>
    <option value="fun">fun</option>
  </select>
  <label for="filter-from">From:</label>
  <input type="date" id="filter-from">
  <label for="filter-to">To:</label>
  <input type="date" id="filter-to">
</div>

<div id="expense-list"></div>

<div class="summary">
  <div>Total: $<span id="total">0.00</span></div>
  <div id="cat-totals">
    <span class="cat-total" data-cat="groceries">groceries: $0.00</span>
    <span class="cat-total" data-cat="transport">transport: $0.00</span>
    <span class="cat-total" data-cat="bills">bills: $0.00</span>
    <span class="cat-total" data-cat="fun">fun: $0.00</span>
  </div>
</div>

<script>
(() => {
  const categories = ['groceries','transport','bills','fun'];
  const storageKey = 'expenses';
  let expenses = [];

  const amountEl = document.getElementById('amount');
  const categoryEl = document.getElementById('category');
  const dateEl = document.getElementById('date');
  const noteEl = document.getElementById('note');
  const addBtn = document.getElementById('add-expense');
  const formErrorEl = document.getElementById('form-error');
  const listEl = document.getElementById('expense-list');
  const totalEl = document.getElementById('total');
  const filterCatEl = document.getElementById('filter-category');
  const filterFromEl = document.getElementById('filter-from');
  const filterToEl = document.getElementById('filter-to');

  function load() {
    const data = localStorage.getItem(storageKey);
    if (data) expenses = JSON.parse(data);
    render();
  }

  function save() {
    localStorage.setItem(storageKey, JSON.stringify(expenses));
  }

  function render() {
    // sort newest first (by id timestamp)
    const sorted = [...expenses].sort((a,b)=>b.id-a.id);
    listEl.innerHTML = '';
    sorted.forEach(exp => {
      const row = document.createElement('div');
      row.className = 'expense';
      row.dataset.id = exp.id;
      row.dataset.category = exp.category;
      row.dataset.date = exp.date; // ISO string YYYY-MM-DD

      const amountSpan = document.createElement('span');
      amountSpan.textContent = `$${Number(exp.amount).toFixed(2)}`;
      const catSpan = document.createElement('span');
      catSpan.textContent = exp.category;
      const dateSpan = document.createElement('span');
      dateSpan.textContent = exp.date;
      const noteSpan = document.createElement('span');
      noteSpan.textContent = exp.note ? `(${exp.note})` : '';
      const delBtn = document.createElement('button');
      delBtn.className = 'exp-del';
      delBtn.textContent = '✖';
      delBtn.dataset.id = exp.id;

      row.append(amountSpan, catSpan, dateSpan, noteSpan, delBtn);
      listEl.appendChild(row);
    });
    applyFilters();
  }

  function addExpense() {
    const amountVal = amountEl.value.trim();
    const dateVal = dateEl.value.trim();

    // Validation
    if (!amountVal || isNaN(amountVal) || Number(amountVal) <= 0) {
      formErrorEl.textContent = 'Please enter a positive amount.';
      return;
    }
    if (!dateVal) {
      formErrorEl.textContent = 'Please select a date.';
      return;
    }

    const expense = {
      id: Date.now(),
      amount: Number(amountVal).toFixed(2),
      category: categoryEl.value,
      date: dateVal,
      note: noteEl.value.trim()
    };
    expenses.push(expense);
    save();
    render();

    // reset form
    formErrorEl.textContent = '';
    amountEl.value = '';
    // keep other fields as is (optional)
  }

  function deleteExpense(id) {
    expenses = expenses.filter(e => e.id !== id);
    save();
    render();
  }

  function applyFilters() {
    const catFilter = filterCatEl.value;
    const fromVal = filterFromEl.value;
    const toVal = filterToEl.value;

    const rows = listEl.querySelectorAll('.expense');
    rows.forEach(row => {
      const rowCat = row.dataset.category;
      const rowDate = row.dataset.date; // YYYY-MM-DD

      let show = true;
      if (catFilter !== 'all' && rowCat !== catFilter) show = false;
      if (fromVal && rowDate < fromVal) show = false;
      if (toVal && rowDate > toVal) show = false;

      row.style.display = show ? '' : 'none';
    });
    updateTotals();
  }

  function updateTotals() {
    const visibleRows = listEl.querySelectorAll('.expense:not([style*="display: none"])');
    let total = 0;
    const catSums = {groceries:0, transport:0, bills:0, fun:0};

    visibleRows.forEach(row => {
      const amount = parseFloat(row.children[0].textContent.replace('$',''));
      const cat = row.dataset.category;
      total += amount;
      if (cat in catSums) catSums[cat] += amount;
    });

    totalEl.textContent = total.toFixed(2);
    // update per-category totals
    categories.forEach(cat => {
      const el = document.querySelector(`.cat-total[data-cat="${cat}"]`);
      if (el) el.textContent = `${cat}: $${catSums[cat].toFixed(2)}`;
    });
  }

  // Event listeners
  addBtn.addEventListener('click', addExpense);
  listEl.addEventListener('click', e => {
    if (e.target.classList.contains('exp-del')) {
      const id = Number(e.target.dataset.id);
      deleteExpense(id);
    }
  });
  filterCatEl.addEventListener('change', applyFilters);
  filterFromEl.addEventListener('change', applyFilters);
  filterToEl.addEventListener('change', applyFilters);

  // Initialize
  load();
})();
</script>
</body>
</html>
